query GetGroupedPipes($organizationId: ID!, $search: String, $perPage: Int, $after: String, $filter: PipeFilter!, $tagsUuids: [ID!]) {
  pipesForHome(
    filter: $filter
    organizationId: $organizationId
    search: $search
    tagsUuids: $tagsUuids
  ) {
    __typename
    myPipes(first: $perPage, after: $after) {
      ...myPipes
      ...pageInfo
      ...connectionPipes
      __typename
    }
    otherPipes(first: $perPage, after: $after) {
      ...connectionPipes
      ...pageInfo
      __typename
    }
  }
}
"}

